@inline function sweep_cf_64_pmap_get(s::NTuple{322, UInt64}, k::Int8)::Int8
    k_u = UInt64(reinterpret(UInt8, k))
    count = s[2]
    acc = UInt64(0)
    acc = ifelse((count > UInt64(0)) & (s[3] == k_u), s[4], acc)
    acc = ifelse((count > UInt64(1)) & (s[5] == k_u), s[6], acc)
    acc = ifelse((count > UInt64(2)) & (s[7] == k_u), s[8], acc)
