function cf_demo_64(seed::Int8, lookup::Int8)::Int8
    s = sweep_cf_64_pmap_new()
    s = sweep_cf_64_pmap_set(s, seed + Int8(0), seed + Int8(1))
    s = sweep_cf_64_pmap_set(s, seed + Int8(2), seed + Int8(3))
    s = sweep_cf_64_pmap_set(s, seed + Int8(4), seed + Int8(5))
