@inline function sweep_ls_256_pmap_new()::NTuple{513, UInt64}
    return ntuple(_ -> UInt64(0), Val(513))
end

@inline function sweep_ls_256_pmap_set(s::NTuple{513, UInt64}, k::Int8, v::Int8)::NTuple{513, UInt64}
    count = s[1]
    target = ifelse(count >= UInt64(256), UInt64(255), count)
    new_count = ifelse(count >= UInt64(256), UInt64(256), count + UInt64(1))
    k_u = UInt64(reinterpret(UInt8, k))
    v_u = UInt64(reinterpret(UInt8, v))
