@inline function sweep_ls_1000_pmap_new()::NTuple{2001, UInt64}
    return ntuple(_ -> UInt64(0), Val(2001))
end

@inline function sweep_ls_1000_pmap_set(s::NTuple{2001, UInt64}, k::Int8, v::Int8)::NTuple{2001, UInt64}
    count = s[1]
    target = ifelse(count >= UInt64(1000), UInt64(999), count)
    new_count = ifelse(count >= UInt64(1000), UInt64(1000), count + UInt64(1))
    k_u = UInt64(reinterpret(UInt8, k))
    v_u = UInt64(reinterpret(UInt8, v))
    return (
        new_count,
        ifelse(target == UInt64(0), k_u, s[2]),
        ifelse(target == UInt64(0), v_u, s[3]),
